+function shouldIgnoreScannedDirectory(dirName: string): boolean {
+  const normalized = dirName.trim().toLowerCase();
+  if (!normalized) {
+    return true;
+  }
+  if (normalized.endsWith(".bak")) {
+    return true;
+  }
+  if (normalized.includes(".backup-")) {
+    return true;
+  }
+  if (normalized.includes(".disabled")) {
+    return true;
+  }
+  return false;
+}
